tinymce.PluginManager.requireLangPack("mc_cat");tinymce.PluginManager.add("mc_cat",(function(editor,url){const _=text=>editor.translate(text);const categorySvg=`<svg width="24" height="24" viewBox="0 0 24 24">\n        <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z" fill-rule="nonzero"/>\n    </svg>`;editor.ui.registry.addIcon("category",categorySvg);const showDialog=()=>{const parts=editor.id.split("_");const langId=parts.length>1?parts[parts.length-1]:"";const langParam=langId?"&lang_id="+langId:"";const popupUrl=typeof baseadmin!=="undefined"?"/"+baseadmin+"/index.php?controller=Category&action=tinymcePopup"+langParam:"/admin/index.php?controller=Category&action=tinymcePopup"+langParam;editor.windowManager.openUrl({title:_("mc_cat Title")||"Insérer une catégorie",url:popupUrl,width:800,height:550})};editor.ui.registry.addButton("mc_cat",{icon:"category",tooltip:_("mc_cat Tooltip")||"Lien vers une catégorie",onAction:showDialog,onSetup:api=>{const nodeChangeHandler=e=>{api.setEnabled(e.element.nodeName!=="IMG")};editor.on("NodeChange",nodeChangeHandler);return()=>editor.off("NodeChange",nodeChangeHandler)}});editor.ui.registry.addMenuItem("mc_cat",{icon:"category",text:_("mc_cat Title")||"Catégorie",onAction:showDialog})}));